func (r RulesExtra) PrecompileOverride(addr common.Address) (libevm.PrecompiledContract, bool) {
    module, ok := modules.GetPrecompileModuleByAddress(addr)
    if !ok {
        return nil, false
    }
    return makePrecompile(module.Contract), true
}

func setAllowListRole(state StateDB, addr common.Address, role uint8) {
    key := crypto.Keccak256Hash(addr.Bytes())
    value := common.BytesToHash([]byte{role})
    state.SetState(PrecompileAddress, key, value)
}

func (r RulesExtra) CanCreateContract(ac *libevm.AddressContext, gas uint64, state libevm.StateReader) (uint64, error) {
    if r.IsPrecompileEnabled(deployerallowlist.ContractAddress) {
        role := deployerallowlist.GetContractDeployerAllowListStatus(state, ac.Origin)
        if !role.IsEnabled() {
            return 0, fmt.Errorf("tx.origin %s is not authorized to deploy a contract", ac.Origin)
        }
    }
    return gas, nil
}

